query:
cat {{{lookup}}}
| where createdtime > (now () - (1000 * 60 * 60 * 24 * 30))
//| formatdate(tolong(createdtime),"yyyy-MM") as month
| concat(severity,":",severityname) as state 
//| if(isnull(confidence),0,confidence) as confidence"
//| 1 as n | total n as total_insights by entityvalue
| where resolution not in ("False Positive","No Action","Duplicate","")
| values(state) as severity,values(insightid) as ids,values(resolution) as resolutions,sum(riskscore) as total_risk,count as insights, pct(riskscore,50) as med_riskscore,pct(timetoresponse,50) as MTTResponse,pct(timetoremediation,50) as MTTResolution,pct(timetodetection,50) as MTTDetection by entityvalue | sort insights
//| round(avg_riskscore,1) as avg_riskscore | round(avg_confidence,2) as avg_confidence
|round(MTTResponse/60) as MTTResponse | round(MTTResolution/60) as  MTTResolution | round(MTTDetection/60) as MTTDetection
